+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pairs: RelationPair[] };
+
+export type DeferredBuffer = { commands: Command[]; spawned: Set<Entity> };
+
+export function beginDeferred(world: World) {
+    world[$internal].deferredBuffers.push({ commands: [], spawned: new Set() });
+}
+
+export function endDeferred(world: World) {
+    const buffer = world[$internal].deferredBuffers.pop();
+    if (buffer) flushDeferred(world, buffer);
+}
+
+function current(world: World): DeferredBuffer {
+    const buffers = world[$internal].deferredBuffers;
+    let buffer = buffers[buffers.length - 1];
+    if (!buffer) {
+        buffer = { commands: [], spawned: new Set() };
+        buffers.push(buffer);
+    }
+    return buffer;
+}
+
+export function createDeferred(world: World) {
+    return {
+        spawn(...traits: ConfigurableTrait[]) {
+            const ctx = world[$internal];
+            const entity = allocateEntity(ctx.entityIndex);
+            ctx.entityTraits.set(entity, new Set());
+            const buffer = current(world);
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity: Entity) {
+            current(world).commands.push({ type: 'destroy', entity });
+        },
+        add(entity: Entity, ...traits: ConfigurableTrait[]) {
+            current(world).commands.push({ type: 'add', entity, traits });
+        },
+        remove(entity: Entity, ...traits: (Trait | RelationPair)[]) {
+            current(world).commands.push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity: Entity, ...pairs: RelationPair[]) {
+            current(world).commands.push({ type: 'exclusive', entity, pairs });
+        },
+        flush() {
+            const buffer = current(world);
+            flushDeferred(world, buffer);
+            buffer.commands.length = 0;
+            buffer.spawned.clear();
+        },
+    };
+}
+
+/** Flush the nearest buffer that has a command for entity before a direct mutation. */
+export function flushDeferredEntity(world: World, entity: Entity) {
+    const buffers = world[$internal].deferredBuffers;
+    for (let i = buffers.length - 1; i >= 0; i--) {
+        const buffer = buffers[i];
+        if (buffer.commands.some((command) => command.entity === entity)) {
+            flushDeferred(world, buffer);
+            buffer.commands.length = 0;
+            buffer.spawned.clear();
+            return;
+        }
+    }
+}
+
+export function hasDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    return project(world, entity, commands, trait).has;
+}
+
+export function getDeferredTrait(world: World, entity: Entity, trait: Trait | RelationPair): any {
+    const commands = commandsFor(world, entity);
+    if (!commands.length) return undefined;
+    return project(world, entity, commands, trait).value;
