+
+/* A lightweight projection used by Entity.has/get while a buffer is pending. */
+function project(world: World, entity: Entity, commands: Command[], sought: Trait | RelationPair) {
+    let destroyed = false;
+    let has = isRelationPair(sought)
+        ? sought[$internal].target !== '*' && getRelationTargets(world, sought[$internal].relation, entity).includes(sought[$internal].target as Entity)
+        : hasTrait(world, entity, sought);
+    let value = getTrait(world, entity, sought);
+    for (const command of commands) {
+        if (command.type === 'destroy') { destroyed = true; has = false; value = undefined; continue; }
+        if (destroyed) continue;
+        if (command.type === 'add') {
+            for (const config of command.traits) {
+                const target = Array.isArray(config) ? config[0] : config;
+                if (same(target as Trait | RelationPair, sought)) {
+                    has = true;
+                    value = Array.isArray(config) ? config[1] : value;
+                }
+            }
+        } else if (command.type === 'remove') {
+            if (command.traits.some((item) => same(item, sought))) { has = false; value = undefined; }
+        } else if (command.type === 'exclusive') {
+            for (const pair of command.pairs) {
+                if (!isRelationPair(sought) || pair[$internal].relation !== sought[$internal].relation) continue;
+                if (pair[$internal].target === '*' || pair[$internal].target !== sought[$internal].target) { has = false; value = undefined; }
+                else { has = true; value = pair[$internal].params; }
+            }
+        }
+    }
+    return { has: !destroyed && has, value: destroyed ? undefined : value };
+}
+
+function same(a: Trait | RelationPair, b: Trait | RelationPair) {
+    if (isRelationPair(a) || isRelationPair(b)) {
+        return isRelationPair(a) && isRelationPair(b) && a[$internal].relation === b[$internal].relation &&
+            (a[$internal].target === '*' || b[$internal].target === '*' || a[$internal].target === b[$internal].target);
+    }
+    return a === b;
+}
+
+export function flushDeferred(world: World, buffer: DeferredBuffer) {
+    if (!buffer.commands.length) return;
+    const ctx = world[$internal];
+    const destroyed = new Set<Entity>();
+    // A spawn followed by destroy is deliberately invisible, including to subscriptions.
+    for (const command of buffer.commands) if (command.type === 'destroy') destroyed.add(command.entity);
