+    ctx.isFlushingDeferred = true;
+    try {
+        for (const command of buffer.commands) {
+            if (command.type === 'destroy' && command.entity === ctx.worldEntity) {
+                throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+            }
+            if (command.type === 'spawn') {
+                if (destroyed.has(command.entity)) {
+                    ctx.entityTraits.delete(command.entity);
+                    releaseEntity(ctx.entityIndex, command.entity);
+                    continue;
+                }
+                // Deferred entities were allocated early only to provide a stable handle.
+                for (const query of ctx.notQueries) {
+                    const match = query.check(world, command.entity);
+                    if (match) query.add(command.entity);
+                    query.resetTrackingBitmasks(command.entity as number);
+                }
