+function addOrReplace(world: World, entity: Entity, config: ConfigurableTrait) {
+    if (isRelationPair(config)) {
+        const relation = config[$internal].relation;
+        const target = config[$internal].target;
+        if (typeof target === 'number' && getRelationTargets(world, relation, entity).includes(target)) {
+            if (config[$internal].params !== undefined) setTrait(world, entity, config, config[$internal].params);
+        } else addTrait(world, entity, config);
